// Validate and extract input from webhook
const items = $input.all();
const body = items[0].json.body;

// Validate required fields
if (!body.task_description) {
  throw new Error('Missing task_description');
}
if (!body.selected_framework) {
  throw new Error('Missing selected_framework');
}
if (!body.prompt_run_id) {
  throw new Error('Missing prompt_run_id');
}

// Extract data - personality_type and personality_approach are now optional
const personalityType = body.personality_type || null;
const personalityApproach = body.personality_approach || null;
const taskDescription = body.task_description;
const traitPercentages = body.trait_percentages || {};
const selectedFramework = body.selected_framework;
const frameworkReasoning = body.framework_reasoning || '';
const questions = body.framework_questions || [];
const answers = body.clarifying_answers || [];
const promptRunId = body.prompt_run_id;

// Validate personality_approach value if provided
if (personalityApproach && personalityApproach !== 'amplify' && personalityApproach !== 'counterbalance') {
  throw new Error(`Invalid personality_approach value: ${personalityApproach}. Must be 'amplify' or 'counterbalance'`);
}

// Build trait information for context (only if personality type provided)
let traitInfo = '';
if (personalityType && Object.keys(traitPercentages).length > 0) {
  const traitLabels = {
    mind: 'Mind (Introversion/Extraversion)',
    energy: 'Energy (Intuitive/Observant)',
    nature: 'Nature (Thinking/Feeling)',
    tactics: 'Tactics (Judging/Prospecting)',
    identity: 'Identity (Assertive/Turbulent)'
  };

  const formattedTraits = Object.entries(traitPercentages)
    .map(([key, value]) => {
      const label = traitLabels[key] || key;
      return `  - ${label}: ${value}%`;
    })
    .join('\n');

  traitInfo = `\nTrait Percentages:\n${formattedTraits}`;
}

// Build questions and answers
const questionsAndAnswers = questions.map((question, index) => {
  const answer = answers[index];
  return `Q${index + 1}: ${question}\nA${index + 1}: ${answer !== null && answer !== undefined ? answer : '[Skipped]'}`;
}).join('\n\n');

return {
  prompt_run_id: promptRunId,
  personality_type: personalityType,
  has_personality: personalityType !== null,
  personality_approach: personalityApproach,
  task_description: taskDescription,
  trait_percentages: traitPercentages,
  trait_info: traitInfo,
  selected_framework: selectedFramework,
  framework_reasoning: frameworkReasoning,
  questions_and_answers: questionsAndAnswers
};

// Build the system prompt for final optimization
const inputData = $input.first().json;
const hasPersonality = inputData.has_personality;
const personalityApproach = inputData.personality_approach;

let systemPrompt, userMessage;

if (hasPersonality && personalityApproach) {
  // WITH PERSONALITY: Include personality-based approach
  systemPrompt = `You are an expert at crafting AI prompts tailored to personality types based on the 16personalities.com framework.

Your task is to create an optimised, comprehensive AI prompt that:
1. Uses the specified prompt engineering framework as its foundation
2. Applies the designated personality approach strategy:
   ${personalityApproach === 'amplify' ? 
     '**AMPLIFY**: Design the prompt to leverage the user\'s natural personality strengths. Frame instructions in ways that align with their cognitive preferences and communication style. Encourage them to use their natural abilities and thinking patterns.' : 
     '**COUNTERBALANCE**: Design the prompt to provide structure and guidance that compensates for potential personality weaknesses. Include explicit guardrails, step-by-step guidance, and frameworks that help the user approach the task from angles that may not come naturally to them. Be prescriptive and directive.'}
3. Incorporates all provided clarifying answers to add specificity
4. Includes relevant context, constraints, and requirements
5. Specifies desired output format clearly
6. Is clear, specific, actionable, and ready to use

The prompt should be well-structured, comprehensive, and carefully calibrated to maximize effectiveness based on the ${personalityApproach} strategy.

Return ONLY the optimised prompt text, without any preamble, explanation, or commentary. The prompt should be ready to use as-is.`;

  userMessage = `Personality Type: ${inputData.personality_type}${inputData.trait_info}

Task Description:
${inputData.task_description}

Selected Framework: ${inputData.selected_framework}

Personality Approach: ${personalityApproach.toUpperCase()}

Framework Selection Reasoning:
${inputData.framework_reasoning}${inputData.qa_section}

---

Using the ${inputData.selected_framework} framework and the ${personalityApproach.toUpperCase()} approach, create a comprehensive, optimised AI prompt for this task that is perfectly tailored to this user's personality type and requirements.`;

} else {
  // WITHOUT PERSONALITY: Generic framework-based optimization
  systemPrompt = `You are an expert at crafting effective AI prompts using established prompt engineering frameworks.

Your task is to create an optimised, comprehensive AI prompt that:
1. Uses the specified prompt engineering framework as its foundation
2. Incorporates all provided clarifying answers to add specificity
3. Includes relevant context, constraints, and requirements
4. Specifies desired output format clearly
5. Is clear, specific, actionable, and ready to use

The prompt should be well-structured, comprehensive, and optimised for effectiveness using the selected framework.

Return ONLY the optimised prompt text, without any preamble, explanation, or commentary. The prompt should be ready to use as-is.`;

  userMessage = `Task Description:
${inputData.task_description}

Selected Framework: ${inputData.selected_framework}

Framework Selection Reasoning:
${inputData.framework_reasoning}${inputData.qa_section}

---

Using the ${inputData.selected_framework} framework, create a comprehensive, optimised AI prompt for this task.`;
}

return {
  prompt_run_id: inputData.prompt_run_id,
  personality_type: inputData.personality_type,
  has_personality: hasPersonality,
  system_prompt: systemPrompt,
  user_message: userMessage
};

// Handle API error response
const item = $input.first();
const response = item.json;
const webhookData = $node["Build LLM Prompt"].json;

let errorMessage = 'API call failed';
let errorDetails = {};

// Check if this is an n8n error (when continueOnFail is true)
if (response.errorMessage) {
  // n8n error format
  errorMessage = response.errorMessage || 'Unknown error';

  // Add description if available
  if (response.errorDescription) {
    errorDetails.description = response.errorDescription;
    // Use description as main error message if more specific
    if (response.errorDescription !== errorMessage) {
      errorMessage = response.errorDescription;
    }
  }

  // Extract error details
  if (response.errorDetails) {
    // HTTP code
    if (response.errorDetails.httpCode) {
      errorDetails.http_code = response.errorDetails.httpCode;
    }

    // Raw error message (contains the actual API response)
    if (response.errorDetails.rawErrorMessage && response.errorDetails.rawErrorMessage.length > 0) {
      const rawError = response.errorDetails.rawErrorMessage[0];

      // Try to parse if it's a JSON string
      const match = rawError.match(/\{.*\}/);
      if (match) {
        try {
          const parsed = JSON.parse(match[0].replace(/\\/g, ''));
          if (parsed.error) {
            if (parsed.error.type) {
              errorDetails.error_type = parsed.error.type;
            }
            if (parsed.error.message) {
              errorDetails.api_message = parsed.error.message;
              // Use API message as main error if more specific
              if (parsed.error.message !== errorMessage) {
                errorMessage = parsed.error.message;
              }
            }
          }
        } catch (e) {
          // If parsing fails, just store the raw message
          errorDetails.raw_error = rawError;
        }
      }
    }
  }

  // Add n8n-specific details for debugging
  if (response.n8nDetails) {
    errorDetails.node_name = response.n8nDetails.nodeName;
    errorDetails.time = response.n8nDetails.time;
  }
} else if (response.statusCode && response.statusCode !== 200) {
  // HTTP error (non-200 status) without n8n error wrapper
  errorDetails.status_code = response.statusCode;

  if (response.statusMessage) {
    errorDetails.status_message = response.statusMessage;
  }

  // Try to get error from response body
  if (response.body && response.body.error) {
    errorMessage = response.body.error.message || response.body.error.type || errorMessage;
    errorDetails.error_type = response.body.error.type;
  }
}

return {
  prompt_run_id: webhookData.prompt_run_id,
  success: false,
  error: errorMessage,
  details: errorDetails
};

// Extract the optimised prompt from Anthropic response
const items = $input.all();
const response = items[0].json;

let optimisedPrompt = '';

if (response.body.content && response.body.content[0]?.text) {
  optimisedPrompt = response.body.content[0].text.trim();
} else {
  throw new Error('Invalid response from LLM');
}

// Get the original data from the Build LLM Prompt node
const webhookData = $node["Build LLM Prompt"].json;

return {
  optimized_prompt: optimisedPrompt,
  prompt_run_id: webhookData.prompt_run_id,
  personality_type: webhookData.personality_type,
  model_used: response.model || 'claude-3-5-sonnet-20241022',
  tokens_used: {
    input: response.usage?.input_tokens || 0,
    output: response.usage?.output_tokens || 0,
    total: (response.usage?.input_tokens || 0) + (response.usage?.output_tokens || 0)
  }
};
